mapper.select:
select tr.AUTH_RECO_ID, tr.AUTHRES_ID, tr.AUTH_TMPL_NAME AS NODE_NAME, a.CONTR_ID AS UP_TREE_ID, tr.AUTHRES_TYPE from (select t.AUTH_TMPL_ID, t.AUTH_TMPL_NAME, r.AUTH_RECO_ID, r.AUTHRES_ID, r.AUTHRES_TYPE from admin_sm_auth_reco r INNER JOIN admin_sm_data_auth_tmpl t ON r.AUTHRES_ID = t.AUTH_TMPL_ID WHERE r.AUTHOBJ_ID = #{id}
and r.data_tenant_id = #{dataTenantId}
) tr LEFT JOIN admin_sm_data_auth a ON tr.AUTH_TMPL_ID = a.AUTH_TMPL_ID

SELECT t.auth_tmpl_id, t.auth_tmpl_name, t.sql_name, t.sql_string, a.CONTR_ID FROM admin_sm_data_auth_tmpl t LEFT JOIN (select AUTH_ID,CONTR_ID,AUTH_TMPL_ID from admin_sm_data_auth where CONTR_ID = #{contrId}
and DATA_TENANT_ID = #{dataTenantId}
) a on t.AUTH_TMPL_ID = a.AUTH_TMPL_ID ${ew.customSqlSegment}
